import{_ as a,o,c as i,as as t}from"./chunks/framework.Dt0DMeWU.js";const h=JSON.parse('{"title":"第 1 章 Git 概述","description":"","frontmatter":{},"headers":[],"relativePath":"other/Git/Git.md","filePath":"other/Git/Git.md","lastUpdated":1775485159000}'),c={name:"other/Git/Git.md"};function s(n,e,d,p,r,l){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="第-1-章-git-概述" tabindex="-1">第 <code>1</code> 章 <code>Git</code> 概述 <a class="header-anchor" href="#第-1-章-git-概述" aria-label="Permalink to &quot;第 `1` 章 `Git` 概述&quot;">​</a></h1><p><code>Git</code> 是一个免费的、开源的 [[分布式 版本控制 系统]]，可以快速高效地处理从小型到大型的各种项目。</p><p><code>Git</code> 易于学习，占地面积小，性能极快。 它具有廉价的本地库，方便的暂存区域和多个工作流分支等特性。其性能优于 <code>Subversion</code>(<code>svn</code>)、<code>Control Version System</code>、<code>Perforce</code> 和 <code>ClearCase</code> 等版本控制工具。</p><h2 id="_1-何为版本控制" tabindex="-1"><code>1</code>. 何为版本控制 <a class="header-anchor" href="#_1-何为版本控制" aria-label="Permalink to &quot;`1`. 何为版本控制&quot;">​</a></h2><p>版本控制是一种记录文件内容变化，以便将来查阅特定版本修订情况的系统。</p><p>版本控制其实最重要的是可以记录文件修改历史记录，从而让用户能够查看历史版本，方便版本切换。</p><p><img src="https://img.xbin.cn/blog/wps2.jpg" alt="img"></p><h2 id="_2-为什么需要版本控制" tabindex="-1"><code>2</code>. 为什么需要版本控制 <a class="header-anchor" href="#_2-为什么需要版本控制" aria-label="Permalink to &quot;`2`. 为什么需要版本控制&quot;">​</a></h2><p>个人开发过渡到团队协作。</p><p><img src="https://img.xbin.cn/blog/wps6.jpg" alt="img"></p><h2 id="_3-版本控制工具" tabindex="-1"><code>3</code>. 版本控制工具 <a class="header-anchor" href="#_3-版本控制工具" aria-label="Permalink to &quot;`3`. 版本控制工具&quot;">​</a></h2><ul><li><strong>集中式版本控制工具</strong></li></ul><p><code>CVS</code>、<code>SVN</code>(<code>Subversion</code>)、<code>VSS</code>……</p><p>集中化的版本控制系统诸如 <code>CVS</code>、<code>SVN</code> 等，都有一个单一的集中管理的服务器，保存所有文件的修订版本，而协同工作的人们都通过客户端连到这台服务器，取出最新的文件或者提交更新。多年以来，这已成为版本控制系统的标准做法。</p><p>这种做法带来了许多好处，每个人都可以在一定程度上看到项目中的其他人正在做些什么。而管理员也可以轻松掌控每个开发者的权限，并且管理一个集中化的版本控制系统，要远比在各个客户端上维护本地数据库来得轻松容易。</p><p>事分两面，有好有坏。这么做显而易见的缺点是中央服务器的单点故障。如果服务器宕机一小时，那么在这一小时内，谁都无法提交更新，也就无法协同工作。</p><p><img src="https://img.xbin.cn/blog/wps1.jpg" alt="img"></p><ul><li><strong>分布式版本控制工具</strong></li></ul><p><code>Git</code>、<code>Mercurial</code>、<code>Bazaar</code>、<code>Darcs</code>……</p><p>像 <code>Git</code> 这种分布式版本控制工具，客户端提取的不是最新版本的文件快照，而是把代码仓库完整地镜像下来（本地库）。这样任何一处协同工作用的文件发生故障，事后都可以用其他客户端的本地仓库进行恢复。因为每个客户端的每一次文件提取操作，实际上都是一次对整个文件仓库的完整备份。</p><p>分布式的版本控制系统出现之后,解决了集中式版本控制系统的缺陷:</p><p><code>1</code>. 服务器断网的情况下也可以进行开发（因为版本控制是在本地进行的）</p><p><code>2</code>. 每个客户端保存的也都是整个完整的项目（包含历史记录，更加安全）</p><p><img src="https://img.xbin.cn/blog/wps3.jpg" alt="img"></p><h2 id="_4-git-简史" tabindex="-1"><code>4</code>. <code>Git</code> 简史 <a class="header-anchor" href="#_4-git-简史" aria-label="Permalink to &quot;`4`. `Git` 简史&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/wps8.jpg" alt="img"></p><h2 id="_5-git-工作机制" tabindex="-1"><code>5 Git</code> 工作机制 <a class="header-anchor" href="#_5-git-工作机制" aria-label="Permalink to &quot;`5 Git` 工作机制&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/wps7.jpg" alt="img"></p><h2 id="_6-git-和代码托管中心" tabindex="-1"><code>6 Git</code> 和代码托管中心 <a class="header-anchor" href="#_6-git-和代码托管中心" aria-label="Permalink to &quot;`6 Git` 和代码托管中心&quot;">​</a></h2><p>代码托管中心是基于网络服务器的远程代码仓库，一般我们简单称为远程库。</p><ul><li><p><strong>局域网</strong></p><p><code>GitLab</code></p></li><li><p><strong>互联网</strong></p><p><code>GitHub</code>（外网）</p><p><code>Gitee</code> 码云（国内网站）</p></li></ul><h1 id="第-2-章-git-安装" tabindex="-1">第 <code>2</code> 章 <code>Git</code> 安装 <a class="header-anchor" href="#第-2-章-git-安装" aria-label="Permalink to &quot;第 `2` 章 `Git` 安装&quot;">​</a></h1><p>​ 官网地址： <a href="https://git-scm.com/%E6%88%96https://github.com/git-for-windows/git/releases" target="_blank" rel="noreferrer">https://git-scm.com/或https://github.com/git-for-windows/git/releases</a></p><p>​ <strong>推荐安装 <code>git2.40.0</code> 版本</strong></p><p>​ 查看 <code>GNU</code> 协议，可以直接点击下一步。</p><p><img src="https://img.xbin.cn/blog/wps5.jpg" alt="img"></p><p>选择 <code>Git</code> 安装位置，要求是非中文并且没有空格的目录，然后下一步。</p><p><img src="https://img.xbin.cn/blog/wps9.jpg" alt="img"></p><p><code>Git</code> 选项配置，推荐默认设置，然后下一步。</p><p><img src="https://img.xbin.cn/blog/wps10.jpg" alt="img"></p><p><code>Git</code> 安装目录名，不用修改，直接点击下一步。</p><p><img src="https://img.xbin.cn/blog/wps14.jpg" alt="img"></p><p><code>Git</code> 的默认编辑器，建议使用默认的 <code>Vim</code> 编辑器，然后点击下一步。</p><p><img src="https://img.xbin.cn/blog/wps16.jpg" alt="img"></p><p>默认分支名设置，选择让 <code>Git</code> 决定，分支名默认为 <code>master</code>，下一步。</p><p><img src="https://img.xbin.cn/blog/wps13.jpg" alt="img"></p><p>修改 <code>Git</code> 的环境变量，选第一个，不修改环境变量，只在 <code>Git Bash</code> 里使用 <code>Git</code>。</p><p><img src="https://img.xbin.cn/blog/wps11.jpg" alt="img"></p><p>选择后台客户端连接协议，选默认值 <code>OpenSSL</code>，然后下一步。</p><p><img src="https://img.xbin.cn/blog/wps12.jpg" alt="img"></p><p>配置 <code>Git</code> 文件的行末换行符，<code>Windows</code> 使用 <code>CRLF</code>，<code>Linux</code> 使用 <code>LF</code>，选择第一个自动转换，然后继续下一步。</p><p><img src="https://img.xbin.cn/blog/wps15.jpg" alt="img"></p><p>选择 <code>Git</code> 终端类型，选择默认的 <code>Git Bash</code> 终端，然后继续下一步。</p><p><img src="https://img.xbin.cn/blog/wps17.jpg" alt="img"></p><p>选择 <code>Git pull</code> 合并的模式，选择默认，然后下一步。</p><p><img src="https://img.xbin.cn/blog/wps21.jpg" alt="img"></p><p>选择 <code>Git</code> 的凭据管理器，选择默认的跨平台的凭据管理器，然后下一步。</p><p><img src="https://img.xbin.cn/blog/image-20230627170844640.png" alt="img"></p><p>其他配置，选择默认设置，然后下一步。</p><p><img src="https://img.xbin.cn/blog/wps19.jpg" alt="img"></p><p>实验室功能，技术还不成熟，有已知的 <code>bug</code>，不要勾选，然后点击右下角的 <code>Install</code> 按钮，开始安装 <code>Git</code>。</p><p><img src="https://img.xbin.cn/blog/wps22.jpg" alt="img"></p><p>点击 <code>Finsh</code> 按钮，<code>Git</code> 安装成功！</p><p><img src="https://img.xbin.cn/blog/wps18.jpg" alt="img"></p><p>右键任意位置，在右键菜单里选择 <code>Git Bash Here</code> 即可打开 <code>Git Bash</code> 命令行终端。</p><p><img src="https://img.xbin.cn/blog/wps20.jpg" alt="img"></p><p>在 <code>Git Bash</code> 终端里输入 <code>git</code> --<code>version</code> 查看 <code>git</code> 版本，如图所示，说明 <code>Git</code> 安装成功。</p><p><img src="https://img.xbin.cn/blog/image-20230627131804454.png" alt="image-20230627170844640"></p><h1 id="第-3-章-git-常用命令" tabindex="-1">第 <code>3</code> 章 <code>Git</code> 常用命令 <a class="header-anchor" href="#第-3-章-git-常用命令" aria-label="Permalink to &quot;第 `3` 章 `Git` 常用命令&quot;">​</a></h1><table tabindex="0"><thead><tr><th><strong>命令名称</strong></th><th><strong>作用*</strong></th></tr></thead><tbody><tr><td><code>git config</code> --<code>global user.name</code> 用户名</td><td>设置用户签名</td></tr><tr><td><code>git config</code> --<code>global user.email</code> 邮箱</td><td>设置用户邮箱</td></tr><tr><td><code>git init</code></td><td>初始化本地库</td></tr><tr><td><code>git status</code></td><td>查看本地库状态</td></tr><tr><td><code>git add</code> 文件名</td><td>添加到暂存区</td></tr><tr><td><code>git commit</code> -<code>m</code> &quot;日志信息&quot; 文件名</td><td>提交到本地库</td></tr><tr><td><code>git reflog</code></td><td>查看历史记录</td></tr><tr><td><code>git reset</code> --<code>hard</code> 版本号</td><td>版本穿梭</td></tr></tbody></table><h2 id="_1-设置用户签名" tabindex="-1"><code>1</code> 设置用户签名 <a class="header-anchor" href="#_1-设置用户签名" aria-label="Permalink to &quot;`1` 设置用户签名&quot;">​</a></h2><h3 id="_1-1-基本语法" tabindex="-1"><code>1.1</code> 基本语法 <a class="header-anchor" href="#_1-1-基本语法" aria-label="Permalink to &quot;`1.1` 基本语法&quot;">​</a></h3><p><code>git config</code> --<code>global user.name</code> 用户名</p><p><code>git config</code> --<code>global user.email</code> 邮箱</p><h3 id="_1-2-案例实操" tabindex="-1"><code>1.2</code> 案例实操 <a class="header-anchor" href="#_1-2-案例实操" aria-label="Permalink to &quot;`1.2` 案例实操&quot;">​</a></h3><p>全局范围的签名设置：</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Layne</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Layne@atguigu.com</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 查看全局配置</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.gitconfig</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # cat linux中查看文本的命令  ~ 家 [你当前用户的家]/ .gitconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>说明：</p><p>签名的作用是区分不同操作者身份。用户的签名信息在每一个版本的提交信息中能够看到，以此确认本次提交是谁做的。<code>Git</code> 首次安装必须设置一下用户签名，否则无法提交代码。</p><p>※注意：这里设置用户签名和将来登录 <code>GitHub</code>（或其他代码托管中心）的账号没有任何关系。</p><h2 id="_2-初始化本地库" tabindex="-1"><strong><code>2</code></strong> <strong>初始化本地库</strong> <a class="header-anchor" href="#_2-初始化本地库" aria-label="Permalink to &quot;**`2`** **初始化本地库**&quot;">​</a></h2><h3 id="_2-1-基本语法" tabindex="-1"><code>2.1</code> 基本语法 <a class="header-anchor" href="#_2-1-基本语法" aria-label="Permalink to &quot;`2.1` 基本语法&quot;">​</a></h3><p><strong><code>git init</code></strong></p><h3 id="_2-2-案例实操" tabindex="-1"><code>2.2</code> 案例实操 <a class="header-anchor" href="#_2-2-案例实操" aria-label="Permalink to &quot;`2.2` 案例实操&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627132215734.png" alt="image-20230627131721466"></p><p>结果查看</p><p><img src="https://img.xbin.cn/blog/image-20230627132547573.png" alt="image-20230627131804454"></p><h2 id="_3-查看本地库状态" tabindex="-1"><strong><code>3</code></strong> <strong>查看本地库状态</strong> <a class="header-anchor" href="#_3-查看本地库状态" aria-label="Permalink to &quot;**`3`** **查看本地库状态**&quot;">​</a></h2><h3 id="_3-1-基本语法" tabindex="-1"><code>3.1</code> 基本语法 <a class="header-anchor" href="#_3-1-基本语法" aria-label="Permalink to &quot;`3.1` 基本语法&quot;">​</a></h3><p><strong><code>git status</code></strong></p><h3 id="_3-2-案例实操" tabindex="-1"><code>3.2</code> 案例实操 <a class="header-anchor" href="#_3-2-案例实操" aria-label="Permalink to &quot;`3.2` 案例实操&quot;">​</a></h3><h4 id="_1-首次查看-工作区没有文件" tabindex="-1">（<code>1</code>）首次查看（工作区没有文件） <a class="header-anchor" href="#_1-首次查看-工作区没有文件" aria-label="Permalink to &quot;（`1`）首次查看（工作区没有文件）&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627132317963.png" alt="image-20230627132109306"></p><h4 id="_2-新增文件" tabindex="-1">（<code>2</code>）新增文件 <a class="header-anchor" href="#_2-新增文件" aria-label="Permalink to &quot;（`2`）新增文件&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627132109306.png" alt="image-20230627132215734"></p><p><img src="https://img.xbin.cn/blog/image-20230627133425162.png" alt="image-20230627132317963"></p><h4 id="_3-再次查看-检测到未追踪文件" tabindex="-1">（<code>3</code>）再次查看（检测到未追踪文件） <a class="header-anchor" href="#_3-再次查看-检测到未追踪文件" aria-label="Permalink to &quot;（`3`）再次查看（检测到未追踪文件）&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627132954523.png" alt="image-20230627132547573"></p><h2 id="_4-添加暂存区" tabindex="-1"><code>4</code> 添加暂存区 <a class="header-anchor" href="#_4-添加暂存区" aria-label="Permalink to &quot;`4` 添加暂存区&quot;">​</a></h2><h3 id="_4-1-将工作区的文件添加到暂存区" tabindex="-1"><code>4.1</code> 将工作区的文件添加到暂存区 <a class="header-anchor" href="#_4-1-将工作区的文件添加到暂存区" aria-label="Permalink to &quot;`4.1` 将工作区的文件添加到暂存区&quot;">​</a></h3><h4 id="_1-基本语法" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git</code></strong> <strong><code>add</code></strong> <strong>文件名</strong></p><h4 id="_2-案例实操" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627131721466.png" alt="image-20230627132954523"></p><h3 id="_4-2-查看状态-检测到暂存区有新文件" tabindex="-1"><code>4.2</code> 查看状态（检测到暂存区有新文件） <a class="header-anchor" href="#_4-2-查看状态-检测到暂存区有新文件" aria-label="Permalink to &quot;`4.2` 查看状态（检测到暂存区有新文件）&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627133335748.png" alt="image-20230627133040699"></p><h2 id="_5-提交本地库" tabindex="-1"><code>5</code> 提交本地库 <a class="header-anchor" href="#_5-提交本地库" aria-label="Permalink to &quot;`5` 提交本地库&quot;">​</a></h2><h3 id="_5-1-暂存区文件提交到本地库" tabindex="-1"><code>5.1</code> 暂存区文件提交到本地库 <a class="header-anchor" href="#_5-1-暂存区文件提交到本地库" aria-label="Permalink to &quot;`5.1` 暂存区文件提交到本地库&quot;">​</a></h3><h4 id="_1-基本语法-1" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-1" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git commit</code> -<code>m</code> &quot;日志信息&quot; 文件名</strong></p><h4 id="_2-案例实操-1" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-1" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627133937432.png" alt="image-20230627133335748"></p><h3 id="_5-2-查看状态-没有文件需要提交" tabindex="-1"><code>5.2</code> 查看状态（没有文件需要提交） <a class="header-anchor" href="#_5-2-查看状态-没有文件需要提交" aria-label="Permalink to &quot;`5.2` 查看状态（没有文件需要提交）&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627133907417.png" alt="image-20230627133425162"></p><h2 id="_6-修改文件-hello-txt" tabindex="-1"><code>6</code> 修改文件（<code>hello.txt</code>） <a class="header-anchor" href="#_6-修改文件-hello-txt" aria-label="Permalink to &quot;`6` 修改文件（`hello.txt`）&quot;">​</a></h2><h3 id="_6-1-查看状态-检测到工作区有文件被修改" tabindex="-1"><code>6.1</code> 查看状态（检测到工作区有文件被修改） <a class="header-anchor" href="#_6-1-查看状态-检测到工作区有文件被修改" aria-label="Permalink to &quot;`6.1` 查看状态（检测到工作区有文件被修改）&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627133040699.png" alt="image-20230627133644105"></p><h3 id="_6-2-将修改的文件再次添加暂存区" tabindex="-1"><code>6.2</code> 将修改的文件再次添加暂存区 <a class="header-anchor" href="#_6-2-将修改的文件再次添加暂存区" aria-label="Permalink to &quot;`6.2` 将修改的文件再次添加暂存区&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627133644105.png" alt="image-20230627133907417"></p><h3 id="_6-3-查看状态-工作区的修改添加到了暂存区" tabindex="-1"><code>6.3</code> 查看状态（工作区的修改添加到了暂存区） <a class="header-anchor" href="#_6-3-查看状态-工作区的修改添加到了暂存区" aria-label="Permalink to &quot;`6.3` 查看状态（工作区的修改添加到了暂存区）&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627134228811.png" alt="image-20230627133937432"></p><h3 id="_6-4-将暂存区文件提交到本地库" tabindex="-1"><code>6.4</code> 将暂存区文件提交到本地库 <a class="header-anchor" href="#_6-4-将暂存区文件提交到本地库" aria-label="Permalink to &quot;`6.4` 将暂存区文件提交到本地库&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627134046013.png" alt="image-20230627134046013"></p><h2 id="_7-历史版本" tabindex="-1"><code>7</code> 历史版本 <a class="header-anchor" href="#_7-历史版本" aria-label="Permalink to &quot;`7` 历史版本&quot;">​</a></h2><h3 id="_7-1-查看历史版本" tabindex="-1"><code>7.1</code> 查看历史版本 <a class="header-anchor" href="#_7-1-查看历史版本" aria-label="Permalink to &quot;`7.1` 查看历史版本&quot;">​</a></h3><h4 id="_1-基本语法-2" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-2" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git reflog</code></strong> <strong>查看版本信息</strong></p><p><code>git reflog</code> -<code>n</code> 数量</p><p><strong><code>git log</code></strong> <strong>查看版本详细信息</strong></p><h4 id="_2-案例实操-2" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-2" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627134422376.png" alt="image-20230627134228811"></p><h3 id="_7-2-版本穿梭" tabindex="-1"><code>7.2</code> 版本穿梭 <a class="header-anchor" href="#_7-2-版本穿梭" aria-label="Permalink to &quot;`7.2` 版本穿梭&quot;">​</a></h3><h4 id="_1-基本语法-3" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-3" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git reset</code> --<code>hard</code></strong> <strong>版本号</strong></p><h4 id="_2-案例实操-3" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-3" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p>--首先查看当前的历史记录，可以看到当前是在 <code>48f4e22</code> 这个版本</p><p><img src="https://img.xbin.cn/blog/image-20230627134618381.png" alt="image-20230627134422376"></p><p>--切换到之前版本，<code>8ca80d7</code> 版本，也就是我们第一次提交的版本</p><p><img src="https://img.xbin.cn/blog/image-20230627134649667.png" alt="image-20230627134533136"></p><p>--切换完毕之后再查看历史记录，当前成功切换到了 <code>8ca80d7</code> 版本</p><p><img src="https://img.xbin.cn/blog/image-20230627134533136.png" alt="image-20230627134618381"></p><p>--然后查看文件 <code>hello.txt</code>，发现文件内容已经变化</p><p><img src="https://img.xbin.cn/blog/wps25.jpg" alt="image-20230627134649667"></p><p><code>Git</code> 切换版本，底层其实是移动的 <code>HEAD</code> 指针。</p><h1 id="第-4-章-git-分支操作" tabindex="-1">第 <code>4</code> 章 <code>Git</code> 分支操作 <a class="header-anchor" href="#第-4-章-git-分支操作" aria-label="Permalink to &quot;第 `4` 章 `Git` 分支操作&quot;">​</a></h1><p><img src="https://img.xbin.cn/blog/image-20230627135331197.png" alt="img"></p><h2 id="_1-什么是分支" tabindex="-1"><strong><code>1</code></strong> <strong>什么是分支</strong> <a class="header-anchor" href="#_1-什么是分支" aria-label="Permalink to &quot;**`1`** **什么是分支**&quot;">​</a></h2><p>在版本控制过程中，同时推进多个任务，为每个任务，我们就可以创建每个任务的单独分支。使用分支意味着程序员可以把自己的工作从开发主线上分离开来，开发自己分支的时候，不会影响主线分支的运行。对于初学者而言，分支可以简单理解为副本，一个分支就是一个单独的副本。（分支底层其实也是指针的引用）</p><p><img src="https://img.xbin.cn/blog/image-20230627135136847.png" alt="img"></p><h2 id="_2-分支的好处" tabindex="-1"><strong><code>2</code></strong> <strong>分支的好处</strong> <a class="header-anchor" href="#_2-分支的好处" aria-label="Permalink to &quot;**`2`** **分支的好处**&quot;">​</a></h2><p>同时并行推进多个功能开发，提高开发效率。</p><p>各个分支在开发过程中，如果某一个分支开发失败，不会对其他分支有任何影响。失败的分支删除重新开始即可。</p><h2 id="_3-分支的操作" tabindex="-1"><strong><code>3</code></strong> <strong>分支的操作</strong> <a class="header-anchor" href="#_3-分支的操作" aria-label="Permalink to &quot;**`3`** **分支的操作**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>命令名称</strong></th><th><strong>作用</strong></th></tr></thead><tbody><tr><td><code>git branch</code> 分支名</td><td>创建分支</td></tr><tr><td><code>git branch</code> -<code>v</code></td><td>查看分支</td></tr><tr><td><code>git checkout</code> 分支名</td><td>切换分支</td></tr><tr><td><code>git merge</code> 分支名</td><td>把指定的分支合并到当前分支上</td></tr></tbody></table><h3 id="_3-1-查看分支" tabindex="-1"><code>3.1</code> 查看分支 <a class="header-anchor" href="#_3-1-查看分支" aria-label="Permalink to &quot;`3.1` 查看分支&quot;">​</a></h3><h4 id="_1-基本语法-4" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-4" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git branch</code> -<code>v</code></strong></p><h4 id="_2-案例实操-4" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-4" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627160720264.png" alt="image-20230627135136847"></p><h3 id="_3-2-创建分支" tabindex="-1"><code>3.2</code> 创建分支 <a class="header-anchor" href="#_3-2-创建分支" aria-label="Permalink to &quot;`3.2` 创建分支&quot;">​</a></h3><h4 id="_1-基本语法-5" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-5" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git branch</code></strong> <strong>分支名</strong></p><h4 id="_2-案例实操-5" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-5" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627160758345.png" alt="image-20230627135331197"></p><h3 id="_3-3-修改分支" tabindex="-1"><code>3.3</code> 修改分支 <a class="header-anchor" href="#_3-3-修改分支" aria-label="Permalink to &quot;`3.3` 修改分支&quot;">​</a></h3><p>--在 <code>maste</code> 分支上做修改</p><p><img src="https://img.xbin.cn/blog/image-20230627160605046.png" alt="image-20230627160605046"></p><p>--添加暂存区</p><p><img src="https://img.xbin.cn/blog/image-20230627161238145.png" alt="image-20230627160641155"></p><p>--提交本地库</p><p><img src="https://img.xbin.cn/blog/image-20230627161146988.png" alt="image-20230627160720264"></p><p>--查看分支</p><p><img src="https://img.xbin.cn/blog/image-20230627160840253.png" alt="image-20230627160758345"></p><p>--查看 <code>master</code> 分支上的文件内容</p><p><img src="https://img.xbin.cn/blog/image-20230627161502384.png" alt="image-20230627160840253"></p><h3 id="_3-4-切换分支" tabindex="-1"><code>3.4</code> 切换分支 <a class="header-anchor" href="#_3-4-切换分支" aria-label="Permalink to &quot;`3.4` 切换分支&quot;">​</a></h3><h4 id="_1-基本语法-6" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-6" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git checkout</code></strong> <strong>分支名</strong></p><h4 id="_2-案例实操-6" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-6" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p>--分支由 <code>master</code> 改为 <code>hot-fix</code></p><p><img src="https://img.xbin.cn/blog/image-20230627161342861.png" alt="image-20230627161146988"></p><p>--查看 <code>hot-fix</code> 分支上的文件内容发现与 <code>master</code> 分支上的内容不同</p><p><img src="https://img.xbin.cn/blog/image-20230627161412040.png" alt="image-20230627161238145"></p><p>--在 <code>hot-fix</code> 分支上做修改</p><p><img src="https://img.xbin.cn/blog/image-20230627161644314.png" alt="image-20230627161342861"></p><p>--添加暂存区</p><p><img src="https://img.xbin.cn/blog/image-20230627161728843.png" alt="image-20230627161412040"></p><p>--提交本地库</p><p><img src="https://img.xbin.cn/blog/image-20230627160641155.png" alt="image-20230627161502384"></p><h3 id="_3-5-合并分支" tabindex="-1"><code>3.5</code> 合并分支 <a class="header-anchor" href="#_3-5-合并分支" aria-label="Permalink to &quot;`3.5` 合并分支&quot;">​</a></h3><h4 id="_1-基本语法-7" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-7" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git merge</code></strong> <strong>分支名</strong></p><h4 id="_2-案例实操-7" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-7" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p>-- 切换回到 <code>master</code> 分支</p><p><img src="https://img.xbin.cn/blog/image-20230627162115286.png" alt="image-20230627161644314"></p><p>-- 在 <code>master</code> 分支上合并 <code>hot-fix</code> 分支</p><p><img src="https://img.xbin.cn/blog/image-20230627161950153.png" alt="image-20230627161728843"></p><h3 id="_3-6-产生冲突" tabindex="-1"><code>3.6</code> 产生冲突 <a class="header-anchor" href="#_3-6-产生冲突" aria-label="Permalink to &quot;`3.6` 产生冲突&quot;">​</a></h3><h4 id="_1-冲突产生的表现" tabindex="-1">（<code>1</code>）冲突产生的表现 <a class="header-anchor" href="#_1-冲突产生的表现" aria-label="Permalink to &quot;（`1`）冲突产生的表现&quot;">​</a></h4><p>后面状态为 <code>MERGING</code></p><p><img src="https://img.xbin.cn/blog/image-20230627162314679.png" alt="image-20230627161807459"></p><h4 id="_2-冲突产生的原因" tabindex="-1">（<code>2</code>）冲突产生的原因 <a class="header-anchor" href="#_2-冲突产生的原因" aria-label="Permalink to &quot;（`2`）冲突产生的原因&quot;">​</a></h4><p>合并分支时，两个分支在<strong>同一个文件的同一个位置</strong>有两套完全不同的修改。<code>Git</code> 无法替我们决定使用哪一个。必须<strong>人为决定</strong>新代码内容。</p><p>查看状态（检测到有文件有两处修改）</p><p><img src="https://img.xbin.cn/blog/image-20230627162209093.png" alt="image-20230627161950153"></p><h3 id="_3-7-解决冲突" tabindex="-1"><code>3.7</code> 解决冲突 <a class="header-anchor" href="#_3-7-解决冲突" aria-label="Permalink to &quot;`3.7` 解决冲突&quot;">​</a></h3><h4 id="_1-编辑有冲突的文件" tabindex="-1">（<code>1</code>）编辑有冲突的文件 <a class="header-anchor" href="#_1-编辑有冲突的文件" aria-label="Permalink to &quot;（`1`）编辑有冲突的文件&quot;">​</a></h4><p>删除特殊符号，决定要使用的内容</p><p>特殊符号：&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD 当前分支的代码 ======= 合并过来的代码 &gt;&gt;&gt;&gt;&gt;&gt;&gt; <code>hot-fix</code></p><p><img src="https://img.xbin.cn/blog/wps27.jpg" alt="image-20230627162115286"></p><h4 id="_2-添加到暂存区" tabindex="-1">（<code>2</code>）添加到暂存区 <a class="header-anchor" href="#_2-添加到暂存区" aria-label="Permalink to &quot;（`2`）添加到暂存区&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627161807459.png" alt="image-20230627162209093"></p><h4 id="_3-执行提交" tabindex="-1">（<code>3</code>）执行提交 <a class="header-anchor" href="#_3-执行提交" aria-label="Permalink to &quot;（`3`）执行提交&quot;">​</a></h4><p>注意：此时使用 <code>git commit</code> 命令时<strong>不能带文件名</strong></p><p><img src="https://img.xbin.cn/blog/wps29.jpg" alt="image-20230627162314679"></p><p>--发现后面 <code>MERGING</code> 消失，变为正常</p><h2 id="_4-创建分支和切换分支图解" tabindex="-1"><code>4</code> 创建分支和切换分支图解 <a class="header-anchor" href="#_4-创建分支和切换分支图解" aria-label="Permalink to &quot;`4` 创建分支和切换分支图解&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/wps32.jpg" alt="img"></p><p><code>master</code>、<code>hot-fix</code> 其实都是指向具体版本记录的指针。当前所在的分支，其实是由 <code>HEAD</code> 决定的。所以创建分支的本质就是多创建一个指针。</p><p><code>HEAD</code> 如果指向 <code>master</code>，那么我们现在就在 <code>master</code> 分支上，<code>HEAD</code> 如果执行 <code>hotfix</code>，那么我们现在就在 <code>hotfix</code> 分支上。</p><p>所以切换分支的本质就是移动 <code>HEAD</code> 指针。</p><h1 id="第-5-章-gitee-码云-操作" tabindex="-1">第 <code>5</code> 章 <code>Gitee</code>（码云）操作 <a class="header-anchor" href="#第-5-章-gitee-码云-操作" aria-label="Permalink to &quot;第 `5` 章 `Gitee`（码云）操作&quot;">​</a></h1><h2 id="_1-git-代码托管服务" tabindex="-1"><strong><code>1 Git</code> 代码托管服务</strong> <a class="header-anchor" href="#_1-git-代码托管服务" aria-label="Permalink to &quot;**`1 Git` 代码托管服务**&quot;">​</a></h2><p>前面我们已经知道了 <code>Git</code> 中存在两种类型的仓库，即<strong>本地仓库</strong>和<strong>远程仓库</strong>。那么我们如何搭建 <code>Git</code> 远程仓库呢？我们可以借助互联网上提供的一些代码托管服务来实现，其中比较常用的有 <code>GitHub</code>、码云、<code>GitLab</code> 等。</p><p><code>l gitHub</code>（ 地址：<a href="https://github.com/" target="_blank" rel="noreferrer">https://github.com/</a> ）</p><p>是一个面向开源及私有软件项目的托管平台，因为只支持 <code>Git</code> 作为唯一的版本库格式进行托管，故名 <code>gitHub</code></p><p><code>l</code> 码云（地址： <a href="https://gitee.com/" target="_blank" rel="noreferrer">https://gitee.com/</a> ）</p><p>是<strong>国内</strong>的一个代码托管平台，由于服务器在国内，所以相比于 <code>GitHub</code>，码云速度会更快</p><p><code>l GitLab</code> （地址： <a href="https://about.gitlab.com/" target="_blank" rel="noreferrer">https://about.gitlab.com/</a> ）</p><p>是一个用于仓库管理系统的开源项目，使用 <code>Git</code> 作为代码管理工具，并在此基础上搭建起来的 <code>web</code> 服务</p><h2 id="_2-gitee-简介" tabindex="-1"><strong><code>2 Gitee</code> 简介</strong> <a class="header-anchor" href="#_2-gitee-简介" aria-label="Permalink to &quot;**`2 Gitee` 简介**&quot;">​</a></h2><p><code>1</code>.是什么： <code>gitee</code> 是一个 <code>git</code> 项目托管网站，主要提供基于 <code>git</code> 的版本托管服务</p><p><code>2</code>.能干嘛： <code>gitee</code> 是一个基于 <code>git</code> 的代码托管平台， <code>Git</code> 并不像 <code>SVN</code> 那样有个中心服务器。目前我们使用到的 <code>Git</code> 命令都是在本地执行，如果你想通过 <code>Git</code> 分享你的代码或者与其他开发人员合作。 你就需要将数据放到一台其他开发人员能够连接的服务器上。</p><p><img src="https://img.xbin.cn/blog/wps30.jpg" alt="img"></p><p><code>3</code>.去哪下： <a href="https://gitee.com/" target="_blank" rel="noreferrer">https://gitee.com/</a></p><p><code>4</code>.怎么玩：见课堂演示</p><p>前面执行的命令操作都是针对的本地仓库，本章节我们会学习关于远程仓库的一些操作，具体包括：</p><p><code>l</code> 查看远程仓库</p><p><code>l</code> 添加远程仓库</p><p><code>l</code> 从远程仓库克隆</p><p><code>l</code> 从远程仓库中抓取与拉取</p><p><code>l</code> 推送到远程仓库</p><h2 id="_3-码云帐号注册和登录" tabindex="-1"><strong><code>3</code></strong> 码云帐号注册和登录 <a class="header-anchor" href="#_3-码云帐号注册和登录" aria-label="Permalink to &quot;**`3`** 码云帐号注册和登录&quot;">​</a></h2><p>进入码云官网地址：<a href="https://gitee.com/%EF%BC%8C%E7%82%B9%E5%87%BB%E6%B3%A8%E5%86%8C" target="_blank" rel="noreferrer">https://gitee.com/，点击注册</a> <code>Gitee</code></p><p><img src="https://img.xbin.cn/blog/wps28.jpg" alt="img"></p><p>​ 输入个人信息，进行注册即可。</p><p><img src="https://img.xbin.cn/blog/image-20230627163625061.png" alt="img"></p><p>​ 帐号注册成功以后，直接登录。</p><p><img src="https://img.xbin.cn/blog/image-20230627163438184.png" alt="img"> 登录以后，就可以看到码云官网首页了。</p><p><img src="https://img.xbin.cn/blog/image-20230627163519780.png" alt="img"></p><h2 id="_4-创建远程仓库" tabindex="-1"><code>4</code> 创建远程仓库 <a class="header-anchor" href="#_4-创建远程仓库" aria-label="Permalink to &quot;`4` 创建远程仓库&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/wps33.jpg" alt="img"></p><p><img src="https://img.xbin.cn/blog/image-20230627164135658.png" alt="image-20230627163438184"></p><p><img src="https://img.xbin.cn/blog/image-20230627163710074.png" alt="image-20230627163519780"></p><h2 id="_5-远程仓库操作" tabindex="-1"><code>5</code> 远程仓库操作 <a class="header-anchor" href="#_5-远程仓库操作" aria-label="Permalink to &quot;`5` 远程仓库操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>命令名称*</strong></th><th><strong>作用</strong></th></tr></thead><tbody><tr><td><code>git remote</code> -<code>v</code></td><td>查看当前所有远程地址别名</td></tr><tr><td><code>git remote add</code> 别名 远程地址</td><td>起别名</td></tr><tr><td><code>git push</code> 别名 分支(本地分支名)</td><td>推送本地分支上的内容到远程仓库</td></tr><tr><td><code>git clone</code> 远程地址</td><td>将远程仓库的内容克隆到本地</td></tr><tr><td><code>git pull</code> 远程库地址别名 远程分支名</td><td>将远程仓库对于分支最新内容拉下来后与当前本地分支直接合并</td></tr></tbody></table><h3 id="_5-1-创建远程仓库别名" tabindex="-1"><code>5.1</code> 创建远程仓库别名 <a class="header-anchor" href="#_5-1-创建远程仓库别名" aria-label="Permalink to &quot;`5.1` 创建远程仓库别名&quot;">​</a></h3><h4 id="_1-基本语法-8" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-8" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git remote</code> -<code>v</code></strong> <strong>查看当前所有远程地址别名</strong></p><p><strong><code>git remote add</code></strong> <strong>别名</strong> <strong>远程地址</strong></p><h4 id="_2-案例实操-8" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-8" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627163829931.png" alt="image-20230627163625061"></p><p><strong><a href="https://gitee.com/boncda/git-demo1.git" target="_blank" rel="noreferrer">https://gitee.com/boncda/git-demo1.git</a></strong></p><p><strong>**这个地址在创建完远程仓库后生成的连接，如图所示红框中**</strong></p><p><img src="https://img.xbin.cn/blog/image-20230627164353109.png" alt="image-20230627163710074"></p><h3 id="_5-2-推送本地分支到远程仓库" tabindex="-1"><code>5.2</code> 推送本地分支到远程仓库 <a class="header-anchor" href="#_5-2-推送本地分支到远程仓库" aria-label="Permalink to &quot;`5.2` 推送本地分支到远程仓库&quot;">​</a></h3><h4 id="_1-基本语法-9" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-9" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git push</code></strong> <strong>别名</strong> <strong>分支</strong></p><h4 id="_2-案例实操-9" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-9" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/image-20230627163920349.png" alt="image-20230627163829931"></p><p>第一次需要输入<strong>码云的用户名和密码</strong></p><p>此时发现已将我们 <code>master</code> 分支上的内容推送到 <code>Gitee</code> 创建的远程仓库。</p><p><img src="https://img.xbin.cn/blog/wps42.jpg" alt="image-20230627163920349"></p><h3 id="_5-3-克隆远程仓库到本地" tabindex="-1"><code>5.3</code> 克隆远程仓库到本地 <a class="header-anchor" href="#_5-3-克隆远程仓库到本地" aria-label="Permalink to &quot;`5.3` 克隆远程仓库到本地&quot;">​</a></h3><h4 id="_1-基本语法-10" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-10" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git clone</code></strong> <strong>远程地址</strong></p><h4 id="_2-案例实操-10" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-10" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><strong>创建新文件夹，执行</strong></p><p><img src="https://img.xbin.cn/blog/image-20230627164105896.png" alt="image-20230627164105896"></p><p>这个地址为远程仓库地址，克隆结果：初始化本地仓库</p><p><img src="https://img.xbin.cn/blog/wps31.jpg" alt="image-20230627164135658"></p><p>进入 <code>git-demo1</code> 执行</p><p><img src="https://img.xbin.cn/blog/wps45.jpg" alt="image-20230627164353109"></p><p>小结：<code>clone</code> 会做如下操作。<code>1</code>、拉取代码。<code>2</code>、初始化本地仓库。<code>3</code>、创建别名</p><h3 id="_5-4-邀请加入团队" tabindex="-1"><code>5.4</code> 邀请加入团队 <a class="header-anchor" href="#_5-4-邀请加入团队" aria-label="Permalink to &quot;`5.4` 邀请加入团队&quot;">​</a></h3><h4 id="_1-点击管理" tabindex="-1"><strong>（<code>1</code>）点击管理</strong> <a class="header-anchor" href="#_1-点击管理" aria-label="Permalink to &quot;**（`1`）点击管理**&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/wps43.jpg" alt="img"></p><h4 id="_2-选择仓库成员管理" tabindex="-1">（<code>2</code>）选择仓库成员管理 <a class="header-anchor" href="#_2-选择仓库成员管理" aria-label="Permalink to &quot;（`2`）选择仓库成员管理&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/wps46.jpg" alt="img"></p><h4 id="_3-选择邀请用户" tabindex="-1">（<code>3</code>）选择邀请用户 <a class="header-anchor" href="#_3-选择邀请用户" aria-label="Permalink to &quot;（`3`）选择邀请用户&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/wps44.jpg" alt="img"></p><h4 id="_4-有多种方式可以添加" tabindex="-1">（<code>4</code>）有多种方式可以添加 <a class="header-anchor" href="#_4-有多种方式可以添加" aria-label="Permalink to &quot;（`4`）有多种方式可以添加&quot;">​</a></h4><p>下面演示直接添加</p><p><img src="https://img.xbin.cn/blog/wps49.jpg" alt="img"></p><p>直接输入用户名称添加</p><p><img src="https://img.xbin.cn/blog/wps48.jpg" alt="img"></p><p>指定权限，提交</p><p><img src="https://img.xbin.cn/blog/wps47.jpg" alt="img"></p><p><img src="https://img.xbin.cn/blog/wps51.jpg" alt="img"></p><p><img src="https://img.xbin.cn/blog/wps52.jpg" alt="img"></p><h4 id="_5-测试功能" tabindex="-1">（<code>5</code>）测试功能 <a class="header-anchor" href="#_5-测试功能" aria-label="Permalink to &quot;（`5`）测试功能&quot;">​</a></h4><p>第一，使用 <code>atguiguwz</code> 登录码云，修改文件</p><p><img src="https://img.xbin.cn/blog/wps50.jpg" alt="img"></p><p>第二 <code>atguiguwz</code> 提交文件</p><p>第三 使用另外用户登录，发现文件已经更新</p><p><img src="https://img.xbin.cn/blog/wps58.jpg" alt="img"></p><h3 id="_5-5-拉取远程库内容" tabindex="-1"><code>5.5</code> 拉取远程库内容 <a class="header-anchor" href="#_5-5-拉取远程库内容" aria-label="Permalink to &quot;`5.5` 拉取远程库内容&quot;">​</a></h3><h4 id="_1-基本语法-11" tabindex="-1">（<code>1</code>）基本语法 <a class="header-anchor" href="#_1-基本语法-11" aria-label="Permalink to &quot;（`1`）基本语法&quot;">​</a></h4><p><strong><code>git pull</code></strong> <strong>远程库地址别名</strong> <strong>远程分支名</strong></p><h4 id="_2-案例实操-11" tabindex="-1">（<code>2</code>）案例实操 <a class="header-anchor" href="#_2-案例实操-11" aria-label="Permalink to &quot;（`2`）案例实操&quot;">​</a></h4><p><img src="https://img.xbin.cn/blog/wps54.jpg" alt="img"></p><h2 id="_6-ssh-免密登录-了解" tabindex="-1"><code>6 SSH</code> 免密登录（了解） <a class="header-anchor" href="#_6-ssh-免密登录-了解" aria-label="Permalink to &quot;`6 SSH` 免密登录（了解）&quot;">​</a></h2><p>我们可以看到远程仓库中还有一个 <code>SSH</code> 的地址，因此我们也可以使用 <code>SSH</code> 进行访问。</p><p>你可以按如下命令来生成 <code>sshkey</code>:</p><p><code>ssh-keygen</code> -<code>t ed25519</code> -<code>C</code> &quot;<a href="mailto:xxxxx@xxxxx.com" target="_blank" rel="noreferrer">xxxxx@xxxxx.com</a>&quot;</p><p># <code>Generating public</code>/<code>private ed25519 key pair</code>...</p><p>注意：这里的 <a href="mailto:xxxxx@xxxxx.com" target="_blank" rel="noreferrer">xxxxx@xxxxx.com</a> 只是生成的 <code>sshkey</code> 的名称，并不约束或要求具体命名为某个邮箱。现网的大部分教程均讲解的使用邮箱生成，其一开始的初衷仅仅是为了便于辨识所以使用了邮箱。</p><p>按照提示完成三次回车，即可生成 <code>ssh key</code>。通过查看 ~/.<code>ssh</code>/<code>id_ed25519.pub</code> 文件内容，获取到你的 <code>public key</code></p><p><code>cat</code> ~/.<code>ssh</code>/<code>id_ed25519.pub</code></p><p># <code>ssh-ed25519 AAAAB3NzaC1yc2EAAAADAQABAAABAQC6eNtGpNGwstc</code>....</p><p><img src="https://img.xbin.cn/blog/wps56.jpg" alt="img"></p><p><img src="https://img.xbin.cn/blog/wps59.jpg" alt="img"></p><p>复制生成后的 <code>ssh key</code>，通过仓库主页 <strong>「管理」-&gt;「部署公钥管理」-&gt;「添加部署公钥」</strong> ，添加生成的 <code>public key</code> 添加到仓库中。</p><p><img src="https://img.xbin.cn/blog/wps53.jpg" alt="img"></p><p>添加后，在终端（<code>Terminal</code>）中输入</p><p><code>ssh</code> -<code>T</code> <a href="mailto:git@gitee.com" target="_blank" rel="noreferrer">git@gitee.com</a></p><p>首次使用需要确认并添加主机到本机 <code>SSH</code> 可信列表。若返回 <code>Hi XXX</code>! <code>You</code>&#39;<code>ve successfully authenticated</code>, <code>but Gitee.com does not provide shell access</code>. 内容，则证明添加成功。</p><p><img src="https://img.xbin.cn/blog/image-20230627171156663.png" alt="img"></p><p>添加成功后，就可以使用 <code>SSH</code> 协议对仓库进行操作了。</p><h1 id="第-6-章-idea-集成-git-本地库" tabindex="-1">第 <code>6</code> 章 <code>IDEA</code> 集成 <code>Git</code>（本地库） <a class="header-anchor" href="#第-6-章-idea-集成-git-本地库" aria-label="Permalink to &quot;第 `6` 章 `IDEA` 集成 `Git`（本地库）&quot;">​</a></h1><h2 id="_1-配置-git-忽略文件" tabindex="-1"><code>1</code> 配置 <code>Git</code> 忽略文件 <a class="header-anchor" href="#_1-配置-git-忽略文件" aria-label="Permalink to &quot;`1` 配置 `Git` 忽略文件&quot;">​</a></h2><h3 id="_6-1-idea-特定文件" tabindex="-1"><code>6.1 IDEA</code> 特定文件 <a class="header-anchor" href="#_6-1-idea-特定文件" aria-label="Permalink to &quot;`6.1 IDEA` 特定文件&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/image-20230627171351854.png" alt="img"></p><h3 id="_6-2-maven-工程的-target-目录" tabindex="-1"><code>6.2 Maven</code> 工程的 <code>target</code> 目录 <a class="header-anchor" href="#_6-2-maven-工程的-target-目录" aria-label="Permalink to &quot;`6.2 Maven` 工程的 `target` 目录&quot;">​</a></h3><p><img src="https://img.xbin.cn/blog/wps55.jpg" alt="img"></p><h3 id="_6-3-为什么要忽略他们" tabindex="-1"><code>6.3</code> 为什么要忽略他们 <a class="header-anchor" href="#_6-3-为什么要忽略他们" aria-label="Permalink to &quot;`6.3` 为什么要忽略他们&quot;">​</a></h3><p>与项目的实际功能无关，不参与服务器上部署运行。把它们忽略掉能够屏蔽 <code>IDE</code> 工具之间的差异。</p><h3 id="_6-4-怎么忽略" tabindex="-1"><code>6.4</code> 怎么忽略 <a class="header-anchor" href="#_6-4-怎么忽略" aria-label="Permalink to &quot;`6.4` 怎么忽略&quot;">​</a></h3><h4 id="_1-创建忽略规则文件" tabindex="-1">（<code>1</code>）创建忽略规则文件 <a class="header-anchor" href="#_1-创建忽略规则文件" aria-label="Permalink to &quot;（`1`）创建忽略规则文件&quot;">​</a></h4><ul><li><p><strong>文件名称：<code>xxxx.ignore</code></strong>（前缀名随便起，建议是 <code>git.ignore</code>）</p></li><li><p>这个文件的存放位置原则上在哪里都可以，为了便于让~/.<code>gitconfig</code> 文件引用，建议也放在用户家目录下</p></li><li><p><code>git.ignore</code> 文件模版内容如下</p></li></ul><div class="language-ignore vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ignore</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Compiled class file</span></span>\n<span class="line"><span>*.class</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>erdaye</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># Log file</span></span>\n<span class="line"><span>*.log</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># BlueJ files</span></span>\n<span class="line"><span>*.ctxt</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># Mobile Tools for Java (J2ME)</span></span>\n<span class="line"><span>.mtj.tmp/</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># Package Files #</span></span>\n<span class="line"><span>*.jar</span></span>\n<span class="line"><span>*.war</span></span>\n<span class="line"><span>*.nar</span></span>\n<span class="line"><span>*.ear</span></span>\n<span class="line"><span>*.zip</span></span>\n<span class="line"><span>*.tar.gz</span></span>\n<span class="line"><span>*.rar</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># virtual machine crash logs, see http://www.java.com/en/download/help/error_hotspot.xml</span></span>\n<span class="line"><span>hs_err_pid*</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>.classpath</span></span>\n<span class="line"><span>.project</span></span>\n<span class="line"><span>.settings</span></span>\n<span class="line"><span>target</span></span>\n<span class="line"><span>.idea</span></span>\n<span class="line"><span>*.iml</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br></div></div><h4 id="_2-在-gitconfig-文件中引用" tabindex="-1">（<code>2</code>）在.<code>gitconfig</code> 文件中引用 <a class="header-anchor" href="#_2-在-gitconfig-文件中引用" aria-label="Permalink to &quot;（`2`）在.`gitconfig` 文件中引用&quot;">​</a></h4><p>（此文件在 <code>Windows</code> 的家目录中）</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[user]</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">	name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Layne</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">	email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Layne@atguigu.com</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[core]</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">	excludesfile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/Users/asus/git.ignore</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   \\\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  \\\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  \\\\</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>注意：这里要使用正斜线（/），不要使用反斜线（\\）</p><h2 id="_2-定位-git-程序" tabindex="-1"><code>2</code> 定位 <code>Git</code> 程序 <a class="header-anchor" href="#_2-定位-git-程序" aria-label="Permalink to &quot;`2` 定位 `Git` 程序&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/image-20230627171100646.png" alt="image-20230627171100646"></p><h2 id="_3-初始化本地库" tabindex="-1"><code>3</code> 初始化本地库 <a class="header-anchor" href="#_3-初始化本地库" aria-label="Permalink to &quot;`3` 初始化本地库&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/wps67.jpg" alt="image-20230627171156663"></p><p>选择要创建 <code>Git</code> 本地仓库的工程。</p><p><img src="https://img.xbin.cn/blog/image-20230627171511686.png" alt="image-20230627171258993"></p><h2 id="_4-添加到暂存区" tabindex="-1"><code>4</code> 添加到暂存区 <a class="header-anchor" href="#_4-添加到暂存区" aria-label="Permalink to &quot;`4` 添加到暂存区&quot;">​</a></h2><p>右键点击项目选择 <code>Git</code> -&gt; <code>Add</code> 将项目添加到暂存区。</p><p><img src="https://img.xbin.cn/blog/wps66.jpg" alt="image-20230627171351854"></p><h2 id="_5-提交到本地库" tabindex="-1"><code>5</code> <strong>提交到本地库</strong> <a class="header-anchor" href="#_5-提交到本地库" aria-label="Permalink to &quot;`5` **提交到本地库**&quot;">​</a></h2><p><img src="https://img.xbin.cn/blog/wps70.jpg" alt="image-20230627171511686"></p><h2 id="_6-切换版本" tabindex="-1"><code>6</code> <strong>切换版本</strong> <a class="header-anchor" href="#_6-切换版本" aria-label="Permalink to &quot;`6` **切换版本**&quot;">​</a></h2><p>查看历史版本</p><p><img src="https://img.xbin.cn/blog/wps71.jpg" alt="img"></p><p><img src="https://img.xbin.cn/blog/image-20230627171258993.png" alt="img"></p><p>右键选择要切换的版本，然后在菜单里点击 <code>Checkout Revision</code>。</p><p><img src="https://img.xbin.cn/blog/wps72.jpg" alt="img"></p><h2 id="_7-创建分支" tabindex="-1"><code>7</code> 创建分支 <a class="header-anchor" href="#_7-创建分支" aria-label="Permalink to &quot;`7` 创建分支&quot;">​</a></h2><p>选择 <code>Git</code>，在 <code>Repository</code> 里面，点击 <code>Branches</code> 按钮。</p><p><img src="https://img.xbin.cn/blog/wps69.jpg" alt="img"></p><p>在弹出的 <code>Git Branches</code> 框里，点击 <code>New Branch</code> 按钮。</p><p><img src="https://img.xbin.cn/blog/wps68.jpg" alt="img"></p><p>填写分支名称，创建 <code>hot-fix</code> 分支。</p><p><img src="https://img.xbin.cn/blog/wps77.jpg" alt="img"></p><p>然后看到 <code>hot-fix</code>，说明分支创建成功，并且当前已经切换成 <code>hot-fix</code> 分支</p><p><img src="https://img.xbin.cn/blog/wps75.jpg" alt="img"></p><h2 id="_8-切换分支" tabindex="-1"><code>8</code> <strong>切换分支</strong> <a class="header-anchor" href="#_8-切换分支" aria-label="Permalink to &quot;`8` **切换分支**&quot;">​</a></h2><p>切换到 <code>master</code> 分支</p><p><img src="https://img.xbin.cn/blog/wps76.jpg" alt="img"></p><h2 id="_9-合并分支" tabindex="-1"><code>9</code> <strong>合并分支</strong> <a class="header-anchor" href="#_9-合并分支" aria-label="Permalink to &quot;`9` **合并分支**&quot;">​</a></h2><p>切换到 <code>master</code> 分支，将 <code>hot-fix</code> 分支合并到当前 <code>master</code> 分支。</p><p><img src="https://img.xbin.cn/blog/wps73.jpg" alt="img"></p><p>如果代码没有冲突，分支直接合并成功，分支合并成功以后，代码自动提交，无需手动提交本地库。</p><p><img src="https://img.xbin.cn/blog/wps74.jpg" alt="img"></p><h2 id="_10-解决冲突" tabindex="-1"><code>10</code> <strong>解决冲突</strong> <a class="header-anchor" href="#_10-解决冲突" aria-label="Permalink to &quot;`10` **解决冲突**&quot;">​</a></h2><p>如图所示，如果 <code>master</code> 分支和 <code>hot-fix</code> 分支都修改了代码，在合并分支的时候就会发生冲突。</p><p><img src="https://img.xbin.cn/blog/wps79.jpg" alt="img"></p><p><img src="https://img.xbin.cn/blog/wps78.jpg" alt="img"></p><p>我们现在站在 <code>master</code> 分支上合并 <code>hot-fix</code> 分支，就会发生代码冲突。</p><p><img src="https://img.xbin.cn/blog/wps82.jpg" alt="img"></p><p>点击 <code>Conflicts</code> 框里的 <code>Merge</code> 按钮，进行手动合并代码。</p><p><img src="https://img.xbin.cn/blog/wps84.jpg" alt="img"></p><p>手动合并完代码以后，点击右下角的 <code>Apply</code> 按钮。</p><p><img src="https://img.xbin.cn/blog/wps81.jpg" alt="img"></p><p>代码冲突解决，自动提交本地库。</p><p><img src="https://img.xbin.cn/blog/wps83.jpg" alt="img"></p><h1 id="第-7-章-idea-集成-gitee-码云" tabindex="-1">第 <code>7</code> 章 <code>IDEA</code> 集成 <code>Gitee</code>（码云） <a class="header-anchor" href="#第-7-章-idea-集成-gitee-码云" aria-label="Permalink to &quot;第 `7` 章 `IDEA` 集成 `Gitee`（码云）&quot;">​</a></h1><h2 id="_1-idea-安装码云插件" tabindex="-1"><code>1 IDEA</code> 安装码云插件 <a class="header-anchor" href="#_1-idea-安装码云插件" aria-label="Permalink to &quot;`1 IDEA` 安装码云插件&quot;">​</a></h2><p><code>Idea</code> 默认不带码云插件，我们第一步要安装 <code>Gitee</code> 插件</p><p>如图所示，在 <code>Idea</code> 插件商店搜索 <code>Gitee</code>，然后点击右侧的 <code>Install</code> 按钮。</p><p><img src="https://img.xbin.cn/blog/image-20230627192704469.png" alt="img"></p><p>安装成功后，重启 <code>Idea</code></p><p><img src="https://img.xbin.cn/blog/wps86.jpg" alt="img"></p><p>​ <code>Idea</code> 重启以后在 <code>Version Control</code> 设置里面看到 <code>Gitee</code>，说明码云插件安装成功</p><p><img src="https://img.xbin.cn/blog/wps80.jpg" alt="img"></p><p>​ 然后在码云插件里面添加码云帐号，我们就可以用 <code>Idea</code> 连接码云了。</p><p><img src="https://img.xbin.cn/blog/wps85.jpg" alt="img"></p><p><img src="https://img.xbin.cn/blog/image-20230627192951068.png" alt="img"></p><h2 id="_2-push-推送本地库到远程库" tabindex="-1"><code>2 push</code> 推送本地库到远程库 <a class="header-anchor" href="#_2-push-推送本地库到远程库" aria-label="Permalink to &quot;`2 push` 推送本地库到远程库&quot;">​</a></h2><p>首先在 <code>Idea</code> 里面创建一个工程，初始化 <code>git</code> 工程，然后将代码添加到暂存区，提交到本地库，这些步骤上面已经讲过，此处不再赘述。</p><p>将本地代码 <code>push</code> 到码云远程库</p><p><img src="https://img.xbin.cn/blog/image-20230627192612272.png" alt="image-20230627192612272"></p><p>自定义远程库链接。</p><p><img src="https://img.xbin.cn/blog/image-20230627192906905.png" alt="image-20230627192704469"></p><p>给远程库链接定义个 <code>name</code>，然后再 <code>URL</code> 里面填入码云远程库的链接即可</p><p><img src="https://img.xbin.cn/blog/image-20230627193357500.png" alt="image-20230627192906905"></p><p>然后选择定义好的远程链接，点击 <code>Push</code> 即可</p><p><img src="https://img.xbin.cn/blog/image-20230627193601024.png" alt="image-20230627192951068"></p><p>去码云远程库查看代码。</p><p><img src="https://img.xbin.cn/blog/image-20230627193719625.png" alt="image-20230627193119142"></p><h2 id="_3-pull-拉取远程库到本地库" tabindex="-1"><code>3 pull</code> 拉取远程库到本地库 <a class="header-anchor" href="#_3-pull-拉取远程库到本地库" aria-label="Permalink to &quot;`3 pull` 拉取远程库到本地库&quot;">​</a></h2><p>（<code>1</code>）在码云上直接修改代码内容，之后提交，为了进行测试</p><p><img src="https://img.xbin.cn/blog/image-20230627193119142.png" alt="image-20230627193357500"></p><p>（<code>2</code>）右键点击项目，可以将远程仓库的内容 <code>pull</code> 到本地仓库。</p><p><img src="https://img.xbin.cn/blog/image-20230627193430355.png" alt="image-20230627193430355"></p><p>（<code>3</code>）选择远程库</p><p><img src="https://img.xbin.cn/blog/image-20230627194316698.png" alt="image-20230627193601024"></p><p>（<code>4</code>）<code>pull</code> 了远程库中最新内容</p><p><img src="https://img.xbin.cn/blog/image-20230627194402118.png" alt="image-20230627193719625"></p><p>注意：<code>pull</code> 是拉取远端仓库代码到本地，如果远程库代码和本地库代码不一致，会自动合并，如果自动合并失败，还会涉及到手动解决冲突的问题。</p><h2 id="_4-clone-克隆远程库到本地" tabindex="-1"><code>4 clone</code> 克隆远程库到本地 <a class="header-anchor" href="#_4-clone-克隆远程库到本地" aria-label="Permalink to &quot;`4 clone` 克隆远程库到本地&quot;">​</a></h2><p>（<code>1</code>）选择 <code>Clone</code></p><p><img src="https://img.xbin.cn/blog/image-20230627194205652.png" alt="image-20230627194402118"></p><p>（<code>2</code>）输入远程码云仓库地址</p><p><img src="https://img.xbin.cn/blog/wps26.png" alt="image-20230627194205652"></p><p>（<code>3</code>）完成 <code>clone</code> 操作</p><p><img src="https://img.xbin.cn/blog/wps4.png" alt="image-20230627194316698"></p><p><code>git</code></p>',433)])])}const m=a(c,[["render",s]]);export{h as __pageData,m as default};
